	@Test
	void zeroLengthPathIsTypedAndPreservesEndpointTerms() {
		Var subject = Var.of("subject", VF.createIRI("urn:subject"), true, true);
		Var object = Var.of("object", true);
		Var context = Var.of("context", VF.createIRI("urn:graph"), false, true);
		ZeroLengthPath path = new ZeroLengthPath(Scope.NAMED_CONTEXTS, subject, object, context);

		PlanIr ir = TupleExprToIr.convert(path);

		assertEquals("ZERO_LENGTH_PATH", ir.rootNode().op().name());
		assertEquals("ZeroLengthPathAttr", ir.rootNode().attr().getClass().getSimpleName());
		assertEquals(RuleRootOperator.valueOf("ZERO_LENGTH_PATH"), RuleRootOperator.from(ir.rootNode().op()));
		assertTrue(ir.rootNode().inputs().isEmpty());
		assertTrue(ir.rootNode().semantics().scopeBarrier());

		ZeroLengthPath rendered = (ZeroLengthPath) IrToTupleExpr.convert(ir);
		assertEquals(Scope.NAMED_CONTEXTS, rendered.getScope());
		assertVarEquals(subject, rendered.getSubjectVar());
		assertVarEquals(object, rendered.getObjectVar());
		assertVarEquals(context, rendered.getContextVar());
	}

	@Test
	void arbitraryLengthPathIsTypedWithTransparentPathExpression() {
		Var subject = Var.of("subject", VF.createIRI("urn:subject"), true, true);
		Var object = Var.of("object", true);
		Var context = Var.of("context", VF.createIRI("urn:graph"), false, true);
		StatementPattern step = pattern("stepStart", "predicate", "stepEnd");
		ArbitraryLengthPath path = new ArbitraryLengthPath(Scope.NAMED_CONTEXTS, subject, step, object, context, 3L);

		PlanIr ir = TupleExprToIr.convert(path);
		IrNode root = ir.rootNode();

		assertEquals("ARBITRARY_LENGTH_PATH", root.op().name());
		assertEquals("ArbitraryLengthPathAttr", root.attr().getClass().getSimpleName());
		assertEquals(RuleRootOperator.valueOf("ARBITRARY_LENGTH_PATH"), RuleRootOperator.from(root.op()));
		assertEquals(1, root.inputs().size());
		assertEquals(IrOp.STATEMENT_PATTERN, ir.node(root.inputs().getFirst()).op());
		assertTrue(root.semantics().scopeBarrier());

		ArbitraryLengthPath rendered = (ArbitraryLengthPath) IrToTupleExpr.convert(ir);
		assertEquals(Scope.NAMED_CONTEXTS, rendered.getScope());
		assertEquals(3L, rendered.getMinLength());
		assertVarEquals(subject, rendered.getSubjectVar());
		assertVarEquals(object, rendered.getObjectVar());
		assertVarEquals(context, rendered.getContextVar());
		assertTrue(rendered.getPathExpression() instanceof StatementPattern);
		assertNotSame(step, rendered.getPathExpression());

		PlanIrBuilder replacementBuilder = new PlanIrBuilder(ir.universe());
		IrNodeId empty = replacementBuilder.empty();
		IrNodeId replacedRoot = replacementBuilder.add(root.op(), List.of(empty), root.attr(), root.semantics(),
				root.physical(), root.proofs());
		ArbitraryLengthPath replaced = (ArbitraryLengthPath) IrToTupleExpr
				.convert(replacementBuilder.build(replacedRoot));
		assertTrue(replaced.getPathExpression() instanceof EmptySet,
				"The path definition must remain a transparent independently selectable IR input");
	}

	@Test
	void tripleRefIsTypedAndPreservesEveryTermAndBindingFact() {
		Var subject = Var.of("subject", VF.createIRI("urn:subject"), true, true);
		Var predicate = Var.of("predicate", true);
		Var object = Var.of("object", VF.createLiteral("object"), false, true);
		Var expression = Var.of("triple", false);
		TripleRef tripleRef = new TripleRef(subject, predicate, object, expression);

		PlanIr ir = TupleExprToIr.convert(tripleRef);

		assertEquals("TRIPLE_REF", ir.rootNode().op().name());
		assertEquals("TripleRefAttr", ir.rootNode().attr().getClass().getSimpleName());
		assertEquals(RuleRootOperator.valueOf("TRIPLE_REF"), RuleRootOperator.from(ir.rootNode().op()));
		assertTrue(ir.rootNode().inputs().isEmpty());
		assertFalse(ir.rootNode().semantics().scopeBarrier());
		assertTrue(ir.rootNode().bindings().assured().contains(ir.universe().symbol("predicate")));
		assertTrue(ir.rootNode().bindings().assured().contains(ir.universe().symbol("triple")));
		assertFalse(ir.rootNode().bindings().possible().contains(ir.universe().symbol("subject")),
				"A constant RDF-star term is an input constraint, not an output binding");
		assertFalse(ir.rootNode().bindings().possible().contains(ir.universe().symbol("object")),
				"A constant RDF-star term is an input constraint, not an output binding");

		TripleRef rendered = (TripleRef) IrToTupleExpr.convert(ir);
		assertVarEquals(subject, rendered.getSubjectVar());
		assertVarEquals(predicate, rendered.getPredicateVar());
		assertVarEquals(object, rendered.getObjectVar());
		assertVarEquals(expression, rendered.getExprVar());
	}

