	@Test
	void serviceDefinitionCannotChangeWithoutSynchronizedSourceText() {
		Var endpoint = Var.of("endpoint", VF.createIRI("urn:endpoint"), true, true);
		Map<String, String> prefixes = Map.of("ex", "urn:example:");
		Service service = new Service(endpoint, pattern("s", "p", "o"), "?s ?p ?o .", prefixes,
				"urn:base", true);
		PlanIr ir = TupleExprToIr.convert(service);
		IrNode root = ir.rootNode();

		assertEquals("SERVICE", root.op().name());
		assertEquals("ServiceAttr", root.attr().getClass().getSimpleName());
		assertEquals(RuleRootOperator.valueOf("SERVICE"), RuleRootOperator.from(root.op()));
		assertEquals(1, root.inputs().size());
		assertEquals(IrOp.STATEMENT_PATTERN, ir.node(root.inputs().getFirst()).op());
		assertTrue(root.semantics().scopeBarrier());

		Service rendered = (Service) IrToTupleExpr.convert(ir);
		assertVarEquals(endpoint, rendered.getServiceRef());
		assertEquals(service.getServiceExpr(), rendered.getServiceExpr());
		assertEquals(service.getServiceExpressionString(), rendered.getServiceExpressionString());
		assertEquals(service.getServiceVars(), rendered.getServiceVars());
		assertEquals(prefixes, rendered.getPrefixDeclarations());
		assertEquals("urn:base", rendered.getBaseURI());
		assertTrue(rendered.isSilent());

		PlanIrBuilder replacementBuilder = new PlanIrBuilder(ir.universe());
		IrNodeId replacement = replacementBuilder.empty();
		IllegalStateException failure = assertThrows(IllegalStateException.class,
				() -> replacementBuilder.add(root.op(), List.of(replacement), root.attr(), root.semantics(),
						root.physical(), root.proofs()));
		assertTrue(failure.getMessage().contains("definition input changed independently"));
	}

	@Test
	void unsupportedUnaryRetainsTransparentInputBehindSemanticBarrier() {
		DescribeOperator describe = new DescribeOperator(pattern("s", "p", "o"));

		PlanIr ir = TupleExprToIr.convert(describe);
		IrNode boundary = ir.rootNode();

		assertNotEquals(IrOp.MATERIALIZE, boundary.op(),
				"An unsupported logical boundary must not masquerade as physical materialization");
		assertEquals(1, boundary.inputs().size());
		assertEquals(IrOp.STATEMENT_PATTERN, ir.node(boundary.inputs().getFirst()).op());
		assertTrue(boundary.semantics().scopeBarrier());
		assertTrue(boundary.bindings().assured().contains(ir.universe().symbol("s")));

		PlanIrBuilder replacementBuilder = new PlanIrBuilder(ir.universe());
		IrNodeId replacement = replacementBuilder.empty();
		IrNodeId replacedBoundary = replacementBuilder.add(boundary.op(), List.of(replacement),
				boundary.attr(), boundary.semantics(), boundary.physical(), boundary.proofs());
		assertEquals(BindingShape.empty(), replacementBuilder.node(replacedBoundary).bindings(),
				"Native boundary binding facts must be recomputed from the selected child");
		DescribeOperator rendered = (DescribeOperator) IrToTupleExpr
				.convert(replacementBuilder.build(replacedBoundary));
		assertTrue(rendered.getArg() instanceof EmptySet,
				"Rendering must replace the preserved native child with the selected IR input");
	}

